{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_lMWbtqqe3aCBHyV4TKKfwh","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\tPrice-Volume Divergence Detection for ChiNext (创业板) stocks\n4\tDetects stocks with price new high but volume shrinkage in the last 5 trading days\n5\t\"\"\"\n6\t\n7\timport sys\n8\timport os\n9\tfrom pathlib import Path\n10\t\n11\t# Add YFD project to path\n12\tyfd_path = Path(\"/Users/tomato/Documents/potato/project/YFD\")\n13\tif yfd_path.exists():\n14\t    sys.path.insert(0, str(yfd_path))\n15\t\n16\ttry:\n17\t    import akshare as ak\n18\t    import pandas as pd\n19\t    from datetime import datetime\n20\t    print(\"Successfully imported akshare\")\n21\texcept ImportError as e:\n22\t    print(f\"Import error: {e}\")\n23\t    print(\"Attempting to install akshare...\")\n24\t    import subprocess\n25\t    subprocess.check_call([sys.executable, \"-m\", \"pip\", \"install\", \"akshare\", \"-q\"])\n26\t    import akshare as ak\n27\t    import pandas as pd\n28\t    from datetime import datetime\n29\t\n30\tdef get_chinext_stocks():\n31\t    \"\"\"Get list of ChiNext (创业板) stocks - codes starting with 300/301\"\"\"\n32\t    try:\n33\t        # Get all A-share stocks\n34\t        stock_info = ak.stock_info_a_code_name()\n35\t\n36\t        # Filter for ChiNext stocks (300xxx and 301xxx)\n37\t        chinext = stock_info[stock_info['code'].str.startswith(('300', '301'))]\n38\t\n39\t        print(f\"Found {len(chinext)} ChiNext stocks\")\n40\t        return chinext['code'].tolist()\n41\t    except Exception as e:\n42\t        print(f\"Error getting stock list: {e}\")\n43\t        return []\n44\t\n45\tdef get_stock_data(stock_code, end_date='2024-11-29'):\n46\t    \"\"\"Get historical K-line data for a stock\"\"\"\n47\t    try:\n48\t        # Get daily K-line data\n49\t        df = ak.stock_zh_a_hist(symbol=stock_code, period=\"daily\",\n50\t                                start_date=\"2024-10-01\", end_date=end_date,\n51\t                                adjust=\"qfq\")\n52\t\n53\t        if df is None or len(df) == 0:\n54\t            return None\n55\t\n56\t        # Rename columns to English\n57\t        df = df.rename(columns={\n58\t            '日期': 'date',\n59\t            '最高': 'high',\n60\t            '成交量': 'volume'\n61\t        })\n62\t\n63\t        # Convert date to datetime\n64\t        df['date'] = pd.to_datetime(df['date'])\n65\t\n66\t        # Sort by date\n67\t        df = df.sort_values('date')\n68\t\n69\t        return df[['date', 'high', 'volume']]\n70\t    except Exception as e:\n71\t        return None\n72\t\n73\tdef check_divergence(df):\n74\t    \"\"\"\n75\t    Check if stock meets divergence criteria\n76\t\n77\t    Criteria:\n78\t    1. Price new high: last 5 days max high > first 25 days max high\n79\t    2. Volume shrinkage: last 5 days avg volume < 80% of first 25 days avg volume\n80\t\n81\t    Returns: (meets_criteria, price_change_pct, volume_change_pct, divergence_pct)\n82\t    \"\"\"\n83\t    if df is None or len(df) < 30:\n84\t        return False, None, None, None\n85\t\n86\t    # Get last 30 trading days\n87\t    df_30 = df.tail(30).copy()\n88\t\n89\t    if len(df_30) < 30:\n90\t        return False, None, None, None\n91\t\n92\t    # Split into first 25 days and last 5 days\n93\t    first_25 = df_30.iloc[:25]\n94\t    last_5 = df_30.iloc[25:]\n95\t\n96\t    # Calculate metrics for first 25 days\n97\t    first_25_max_price = first_25['high'].max()\n98\t    first_25_avg_volume = first_25['volume'].mean()\n99\t\n100\t    # Calculate metrics for last 5 days\n101\t    last_5_max_price = last_5['high'].max()\n102\t    last_5_avg_volume = last_5['volume'].mean()\n103\t\n104\t    # Check Condition 1: Price new high (last 5 days max > first 25 days max)\n105\t    price_new_high = last_5_max_price > first_25_max_price\n106\t\n107\t    # Check Condition 2: Volume shrinkage (last 5 days avg < 80% of first 25 days avg)\n108\t    volume_threshold = first_25_avg_volume * 0.8\n109\t    volume_shrinkage = last_5_avg_volume < volume_threshold\n110\t\n111\t    # Calculate the three required metrics\n112\t    # 1. Price change percentage (should be positive)\n113\t    price_change_pct = (last_5_max_price / first_25_max_price - 1) * 100\n114\t\n115\t    # 2. Volume change percentage (should be negative for shrinkage)\n116\t    volume_change_pct = (last_5_avg_volume / first_25_avg_volume - 1) * 100\n117\t\n118\t    # 3. Divergence degree (absolute difference between price change and volume change)\n119\t    divergence_pct = price_change_pct - volume_change_pct\n120\t\n121\t    # Both conditions must be met\n122\t    meets_criteria = price_new_high and volume_shrinkage\n123\t\n124\t    return meets_criteria, price_change_pct, volume_change_pct, divergence_pct\n125\t\n126\tdef main():\n127\t    print(\"=\" * 70)\n128\t    print(\"Price-Volume Divergence Detection for ChiNext Stocks\")\n129\t    print(\"Target date: 2024-11-29\")\n130\t    print(\"=\" * 70)\n131\t\n132\t    # Get ChiNext stock list\n133\t    stock_list = get_chinext_stocks()\n134\t\n135\t    if not stock_list:\n136\t        print(\"Failed to get stock list\")\n137\t        return\n138\t\n139\t    results = []\n140\t    processed = 0\n141\t\n142\t    print(f\"\\nProcessing {len(stock_list)} stocks...\")\n143\t\n144\t    for stock_code in stock_list:\n145\t        processed += 1\n146\t\n147\t        if processed % 100 == 0:\n148\t            print(f\"Processed {processed}/{len(stock_list)} stocks, found {len(results)} with divergence\")\n149\t\n150\t        # Get stock data\n151\t        df = get_stock_data(stock_code, end_date='2024-11-29')\n152\t\n153\t        if df is None:\n154\t            continue\n155\t\n156\t        # Check divergence\n157\t        meets_criteria, price_chg, vol_chg, divergence = check_divergence(df)\n158\t\n159\t        if meets_criteria:\n160\t            results.append({\n161\t                'code': stock_code,\n162\t                'price_change': price_chg,\n163\t                'volume_change': vol_chg,\n164\t                'divergence': divergence\n165\t            })\n166\t            print(f\"  ✓ {stock_code}: price +{price_chg:.2f}%, volume {vol_chg:.2f}%, divergence {divergence:.2f}%\")\n167\t\n168\t    print(f\"\\n{'=' * 70}\")\n169\t    print(f\"Processing complete: {processed} stocks analyzed\")\n170\t    print(f\"Found {len(results)} stocks with price-volume divergence\")\n171\t\n172\t    # Write results to file in the result directory\n173\t    output_path = Path(__file__).parent / \"divergence.txt\"\n174\t\n175\t    with open(output_path, 'w', encoding='utf-8') as f:\n176\t        f.write(\"股票代码,价格涨幅(%),成交量变化(%),背离度(%)\\n\")\n177\t\n178\t        if len(results) == 0:\n179\t            f.write(\"# 无符合条件的股票\\n\")\n180\t        else:\n181\t            # Sort by divergence degree (descending)\n182\t            results.sort(key=lambda x: x['divergence'], reverse=True)\n183\t\n184\t            for r in results:\n185\t                f.write(f\"{r['code']},{r['price_change']:.2f},{r['volume_change']:.2f},{r['divergence']:.2f}\\n\")\n186\t\n187\t    print(f\"Results written to: {output_path}\")\n188\t    print(f\"{'=' * 70}\")\n189\t\n190\tif __name__ == \"__main__\":\n191\t    main()\n192\t\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.\n</system-reminder>\n"}]},"parent_tool_use_id":null,"session_id":"813dbf4a-fe81-4e70-92b1-f24eaa3b52d6","uuid":"d3caee29-dafd-4e00-9f7c-14dd61109816","timestamp":"2026-04-14T12:19:48.037Z","tool_use_result":{"type":"text","file":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_09_price_volume_divergence/revised/claudecode/detect_divergence.py","content":"#!/usr/bin/env python3\n\"\"\"\nPrice-Volume Divergence Detection for ChiNext (创业板) stocks\nDetects stocks with price new high but volume shrinkage in the last 5 trading days\n\"\"\"\n\nimport sys\nimport os\nfrom pathlib import Path\n\n# Add YFD project to path\nyfd_path = Path(\"/Users/tomato/Documents/potato/project/YFD\")\nif yfd_path.exists():\n    sys.path.insert(0, str(yfd_path))\n\ntry:\n    import akshare as ak\n    import pandas as pd\n    from datetime import datetime\n    print(\"Successfully imported akshare\")\nexcept ImportError as e:\n    print(f\"Import error: {e}\")\n    print(\"Attempting to install akshare...\")\n    import subprocess\n    subprocess.check_call([sys.executable, \"-m\", \"pip\", \"install\", \"akshare\", \"-q\"])\n    import akshare as ak\n    import pandas as pd\n    from datetime import datetime\n\ndef get_chinext_stocks():\n    \"\"\"Get list of ChiNext (创业板) stocks - codes starting with 300/301\"\"\"\n    try:\n        # Get all A-share stocks\n        stock_info = ak.stock_info_a_code_name()\n\n        # Filter for ChiNext stocks (300xxx and 301xxx)\n        chinext = stock_info[stock_info['code'].str.startswith(('300', '301'))]\n\n        print(f\"Found {len(chinext)} ChiNext stocks\")\n        return chinext['code'].tolist()\n    except Exception as e:\n        print(f\"Error getting stock list: {e}\")\n        return []\n\ndef get_stock_data(stock_code, end_date='2024-11-29'):\n    \"\"\"Get historical K-line data for a stock\"\"\"\n    try:\n        # Get daily K-line data\n        df = ak.stock_zh_a_hist(symbol=stock_code, period=\"daily\",\n                                start_date=\"2024-10-01\", end_date=end_date,\n                                adjust=\"qfq\")\n\n        if df is None or len(df) == 0:\n            return None\n\n        # Rename columns to English\n        df = df.rename(columns={\n            '日期': 'date',\n            '最高': 'high',\n            '成交量': 'volume'\n        })\n\n        # Convert date to datetime\n        df['date'] = pd.to_datetime(df['date'])\n\n        # Sort by date\n        df = df.sort_values('date')\n\n        return df[['date', 'high', 'volume']]\n    except Exception as e:\n        return None\n\ndef check_divergence(df):\n    \"\"\"\n    Check if stock meets divergence criteria\n\n    Criteria:\n    1. Price new high: last 5 days max high > first 25 days max high\n    2. Volume shrinkage: last 5 days avg volume < 80% of first 25 days avg volume\n\n    Returns: (meets_criteria, price_change_pct, volume_change_pct, divergence_pct)\n    \"\"\"\n    if df is None or len(df) < 30:\n        return False, None, None, None\n\n    # Get last 30 trading days\n    df_30 = df.tail(30).copy()\n\n    if len(df_30) < 30:\n        return False, None, None, None\n\n    # Split into first 25 days and last 5 days\n    first_25 = df_30.iloc[:25]\n    last_5 = df_30.iloc[25:]\n\n    # Calculate metrics for first 25 days\n    first_25_max_price = first_25['high'].max()\n    first_25_avg_volume = first_25['volume'].mean()\n\n    # Calculate metrics for last 5 days\n    last_5_max_price = last_5['high'].max()\n    last_5_avg_volume = last_5['volume'].mean()\n\n    # Check Condition 1: Price new high (last 5 days max > first 25 days max)\n    price_new_high = last_5_max_price > first_25_max_price\n\n    # Check Condition 2: Volume shrinkage (last 5 days avg < 80% of first 25 days avg)\n    volume_threshold = first_25_avg_volume * 0.8\n    volume_shrinkage = last_5_avg_volume < volume_threshold\n\n    # Calculate the three required metrics\n    # 1. Price change percentage (should be positive)\n    price_change_pct = (last_5_max_price / first_25_max_price - 1) * 100\n\n    # 2. Volume change percentage (should be negative for shrinkage)\n    volume_change_pct = (last_5_avg_volume / first_25_avg_volume - 1) * 100\n\n    # 3. Divergence degree (absolute difference between price change and volume change)\n    divergence_pct = price_change_pct - volume_change_pct\n\n    # Both conditions must be met\n    meets_criteria = price_new_high and volume_shrinkage\n\n    return meets_criteria, price_change_pct, volume_change_pct, divergence_pct\n\ndef main():\n    print(\"=\" * 70)\n    print(\"Price-Volume Divergence Detection for ChiNext Stocks\")\n    print(\"Target date: 2024-11-29\")\n    print(\"=\" * 70)\n\n    # Get ChiNext stock list\n    stock_list = get_chinext_stocks()\n\n    if not stock_list:\n        print(\"Failed to get stock list\")\n        return\n\n    results = []\n    processed = 0\n\n    print(f\"\\nProcessing {len(stock_list)} stocks...\")\n\n    for stock_code in stock_list:\n        processed += 1\n\n        if processed % 100 == 0:\n            print(f\"Processed {processed}/{len(stock_list)} stocks, found {len(results)} with divergence\")\n\n        # Get stock data\n        df = get_stock_data(stock_code, end_date='2024-11-29')\n\n        if df is None:\n            continue\n\n        # Check divergence\n        meets_criteria, price_chg, vol_chg, divergence = check_divergence(df)\n\n        if meets_criteria:\n            results.append({\n                'code': stock_code,\n                'price_change': price_chg,\n                'volume_change': vol_chg,\n                'divergence': divergence\n            })\n            print(f\"  ✓ {stock_code}: price +{price_chg:.2f}%, volume {vol_chg:.2f}%, divergence {divergence:.2f}%\")\n\n    print(f\"\\n{'=' * 70}\")\n    print(f\"Processing complete: {processed} stocks analyzed\")\n    print(f\"Found {len(results)} stocks with price-volume divergence\")\n\n    # Write results to file in the result directory\n    output_path = Path(__file__).parent / \"divergence.txt\"\n\n    with open(output_path, 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,价格涨幅(%),成交量变化(%),背离度(%)\\n\")\n\n        if len(results) == 0:\n            f.write(\"# 无符合条件的股票\\n\")\n        else:\n            # Sort by divergence degree (descending)\n            results.sort(key=lambda x: x['divergence'], reverse=True)\n\n            for r in results:\n                f.write(f\"{r['code']},{r['price_change']:.2f},{r['volume_change']:.2f},{r['divergence']:.2f}\\n\")\n\n    print(f\"Results written to: {output_path}\")\n    print(f\"{'=' * 70}\")\n\nif __name__ == \"__main__\":\n    main()\n","numLines":192,"startLine":1,"totalLines":192}}}
